     1→/**
     2→ * Entire CLI checkpoint indexer.
     3→ *
     4→ * Reads the shard-tree produced by `entire commit` on the `entire/checkpoints/v1`
     5→ * branch and writes Checkpoint / CheckpointSession / CheckpointMessage records
     6→ * into the SQLite database.
     7→ *
     8→ * Directory layout expected under the root:
     9→ *   <root>/<shard2>/<id10>/metadata.json
    10→ *   <root>/<shard2>/<id10>/0/metadata.json
    11→ *   <root>/<shard2>/<id10>/0/full.jsonl
    12→ *   <root>/<shard2>/<id10>/1/metadata.json    (if multiple sessions)
    13→ *   <root>/<shard2>/<id10>/1/full.jsonl
    14→ *   ...
    15→ */
    16→
    17→import { readdirSync, readFileSync, existsSync, statSync } from "fs";
    18→import { join } from "path";
    19→import type { PrismaClient } from "../prisma/generated/client/index.js";
    20→import { findCommitForCheckpoint } from "./gitUtils.js";
    21→import { setupLogContentFts, syncLogContentFts } from "./search.js";
    22→
    23→// ─── Raw shapes from the checkpoint files ─────────────────────────────────────
    24→
    25→interface RootMeta {
    26→  cli_version?: string;
    27→  checkpoint_id?: string;
    28→  strategy?: string;
    29→  branch?: string;
    30→  checkpoints_count?: number;
    31→  files_touched?: string[];
    32→  token_usage?: Record<string, unknown>;
    33→}
    34→
    35→interface SummaryLearnings {
    36→  repo?: string[];
    37→  code?: Array<{ path: string; finding: string }>;
    38→  workflow?: string[];
    39→}
    40→
    41→interface SessionSummary {
    42→  intent?: string;
    43→  outcome?: string;
    44→  learnings?: SummaryLearnings;
    45→  friction?: string[];
    46→  open_items?: string[];
    47→}
    48→
    49→interface SessionMeta {
    50→  session_id: string;
    51→  checkpoint_id?: string;
    52→  cli_version?: string;
    53→  strategy?: string;
    54→  created_at?: string;
    55→  branch?: string;
    56→  checkpoints_count?: number;
    57→  turn_id?: string;
    58→  agent?: string;
    59→  token_usage?: Record<string, unknown>;
    60→  initial_attribution?: Record<string, unknown>;
    61→  files_touched?: string[];
    62→  summary?: SessionSummary;
    63→  checkpoint_transcript_start?: number;
    64→  transcript_lines_at_start?: number;
    65→}
    66→
    67→// A single line from full.jsonl — fields vary by type
    68→export interface FullJsonlEvent {
    69→  uuid?: string;
    70→  messageId?: string;      // used by "file-history-snapshot" instead of uuid
    71→  sessionId?: string;
    72→  parentUuid?: string;
    73→  type: string;
    74→  timestamp?: string;
    75→  cwd?: string;
    76→  gitBranch?: string;
    77→  slug?: string;
    78→  version?: string;
    79→  planContent?: string;
    80→  toolUseID?: string;
    81→  parentToolUseID?: string;
    82→  isSidechain?: boolean;
    83→  userType?: string;
    84→  message?: unknown;
    85→  data?: unknown;
    86→  [key: string]: unknown;
    87→}
    88→
    89→// ─── Parsing ──────────────────────────────────────────────────────────────────
    90→
    91→/**
    92→ * Parse a full.jsonl string into an array of event objects.
    93→ * Malformed lines are silently skipped.
    94→ */
    95→export function parseFullJsonl(content: string): FullJsonlEvent[] {
    96→  const out: FullJsonlEvent[] = [];
    97→  for (const line of content.split("\n")) {
    98→    const trimmed = line.trim();
    99→    if (!trimmed) continue;
   100→    try {
   101→      out.push(JSON.parse(trimmed) as FullJsonlEvent);
   102→    } catch {
   103→      // skip malformed line
   104→    }
   105→  }
   106→  return out;
   107→}
   108→
   109→/** Return the unique key for an event, preferring uuid then messageId. */
   110→function eventKey(e: FullJsonlEvent): string | null {
   111→  return e.uuid ?? e.messageId ?? null;
   112→}
   113→
   114→// ─── Git OID mapping helper ───────────────────────────────────────────────────
   115→
   116→async function saveGitOidMapping(
   117→  db: PrismaClient,
   118→  checkpointId: string,
   119→  branch: string | null | undefined,
   120→  repoPath: string,
   121→  existingMappings?: Map<string, string>,
   122→): Promise<void> {
   123→  if (!branch) return;
   124→  try {
   125→    const commit = await findCommitForCheckpoint(repoPath, branch, checkpointId);
   126→    if (!commit) return;
   127→    const existingOid = existingMappings?.get(checkpointId);
   128→    if (existingOid === commit.hash) return; // exact (checkpointId, gitOid) pair already recorded
   129→    // OID is new or changed (e.g. after rebase) — replace old entry if present
   130→    if (existingOid) {
   131→      await db.checkpointIdGitOidJoin.delete({ where: { gitOid: existingOid } }).catch(() => {});
   132→    }
   133→    await db.checkpointIdGitOidJoin.upsert({
   134→      where: { gitOid: commit.hash },
   135→      create: { gitOid: commit.hash, checkpointId },
   136→      update: { checkpointId },
   137→    });
   138→    existingMappings?.set(checkpointId, commit.hash);
   139→  } catch {
   140→    // non-fatal — git may not be available or branch may not exist
   141→  }
   142→}
   143→
   144→// ─── Single-checkpoint indexer ────────────────────────────────────────────────
   145→
   146→/**
   147→ * Index one checkpoint directory (the folder named by the last 10 hex chars,
   148→ * e.g. `<root>/0c/b6cf391c40`).
   149→ *
   150→ * @returns Number of new messages written (already-indexed events are skipped).
   151→ */
   152→
   153→// ─── V2 helpers ───────────────────────────────────────────────────────────────
   154→
   155→async function upsertFilePath(db: PrismaClient, path: string): Promise<number> {
   156→  const existing = await db.filePath.findUnique({ where: { path }, select: { id: true } });
   157→  if (existing) return existing.id;
   158→  const created = await db.filePath.create({ data: { path } });
   159→  return created.id;
   160→}
   161→
   162→async function createTokenUsage(db: PrismaClient, tu: Record<string, unknown>): Promise<number> {
   163→  const row = await db.tokenUsage.create({
   164→    data: {
   165→      inputTokens:         Number(tu.input_tokens          ?? 0),
   166→      cacheCreationTokens: Number(tu.cache_creation_tokens ?? 0),
   167→      cacheReadTokens:     Number(tu.cache_read_tokens     ?? 0),
   168→      outputTokens:        Number(tu.output_tokens         ?? 0),
   169→      apiCallCount:        Number(tu.api_call_count        ?? 0),
   170→    },
   171→  });
   172→  return row.id;
   173→}
   174→
   175→// ─── V2 single-checkpoint indexer ────────────────────────────────────────────
   176→
   177→/**
   178→ * Index one checkpoint directory using the new normalized schema.
   179→ *
   180→ * Reads:
   181→ *   <checkpointDir>/metadata.json             → CheckpointMetadata
   182→ *   <checkpointDir>/<n>/metadata.json         → CheckpointSessionMetadata
   183→ *   <checkpointDir>/<n>/content_hash.txt      → SessionLink.contentHash (actual hash)
   184→ *   <checkpointDir>/<n>/{full.jsonl,context.md,prompt.txt} → SessionLink paths
   185→ */
   186→export async function indexCheckpointV2(
   187→  db: PrismaClient,
   188→  checkpointDir: string,
   189→  checkpointId: string,
   190→  repoPath?: string,
   191→  mappedCheckpointIds?: Set<string>,
   192→): Promise<void> {
   193→  const metaPath = join(checkpointDir, "metadata.json");
   194→  if (!existsSync(metaPath)) throw new Error(`No metadata.json at ${checkpointDir}`);
   195→
   196→  const meta = JSON.parse(readFileSync(metaPath, "utf8")) as RootMeta;
   197→
   198→  // Upsert CheckpointMetadata — create TokenUsage only on first insert
   199→  let checkpointMeta = await db.checkpointMetadata.findUnique({
   200→    where: { checkpointId },
   201→    select: { id: true },
   202→  });
   203→
   204→  if (!checkpointMeta) {
   205→    let tokenUsageId: number | null = null;
   206→    if (meta.token_usage) tokenUsageId = await createTokenUsage(db, meta.token_usage);
   207→    checkpointMeta = await db.checkpointMetadata.create({
   208→      data: {
   209→        checkpointId,
   210→        cliVersion:       meta.cli_version       ?? null,
   211→        branch:           meta.branch            ?? null,
   212→        strategy:         meta.strategy          ?? null,
   213→        checkpointsCount: meta.checkpoints_count ?? 0,
   214→        tokenUsageId,
   215→      },
   216→      select: { id: true },
   217→    });
   218→  } else {
   219→    await db.checkpointMetadata.update({
   220→      where: { checkpointId },
   221→      data: {
   222→        cliVersion:       meta.cli_version       ?? null,
   223→        branch:           meta.branch            ?? null,
   224→        strategy:         meta.strategy          ?? null,
   225→        checkpointsCount: meta.checkpoints_count ?? 0,
   226→      },
   227→    });
   228→  }
   229→
   230→  // files_touched → FilePath + join table
   231→  for (const filePath of meta.files_touched ?? []) {
   232→    const filePathId = await upsertFilePath(db, filePath);
   233→    await db.checkpointMetadataFilePath.upsert({
   234→      where: { checkpointMetadataId_filePathId: { checkpointMetadataId: checkpointMeta.id, filePathId } },
   235→      create: { checkpointMetadataId: checkpointMeta.id, filePathId },
   236→      update: {},
   237→    });
   238→  }
   239→
   240→  // Session sub-directories: 0/, 1/, …
   241→  const sessionDirs = readdirSync(checkpointDir)
   242→    .filter((e) => /^\d+$/.test(e) && statSync(join(checkpointDir, e)).isDirectory())
   243→    .sort((a, b) => parseInt(a) - parseInt(b));
   244→
   245→  for (const sessionDir of sessionDirs) {
   246→    const sessionPath    = join(checkpointDir, sessionDir);
   247→    const metadataFile   = join(sessionPath, "metadata.json");
   248→    const transcriptFile = join(sessionPath, "full.jsonl");
   249→    const contextFile    = join(sessionPath, "context.md");
   250→    const hashFile       = join(sessionPath, "content_hash.txt");
   251→    const promptFile     = join(sessionPath, "prompt.txt");
   252→
   253→    // Read actual hash content (not the file path)
   254→    const contentHash = existsSync(hashFile) ? readFileSync(hashFile, "utf8").trim() : null;
   255→
   256→    const sessionLink = await db.sessionLink.create({
   257→      data: {
   258→        checkpointMetadataId: checkpointMeta.id,
   259→        metadata:   existsSync(metadataFile)   ? metadataFile   : null,
   260→        transcript: existsSync(transcriptFile) ? transcriptFile : null,
   261→        context:    existsSync(contextFile)    ? contextFile    : null,
   262→        contentHash,
   263→        prompt:     existsSync(promptFile)     ? promptFile     : null,
   264→      },
   265→      select: { id: true },
   266→    });
   267→
   268→    if (existsSync(transcriptFile)) {
   269→      await indexFullJsonl(db, transcriptFile, sessionLink.id);
   270→    }
   271→
   272→    if (!existsSync(metadataFile)) continue;
   273→
   274→    const sessionMeta = JSON.parse(readFileSync(metadataFile, "utf8")) as SessionMeta;
   275→    const { session_id: sessionId } = sessionMeta;
   276→    if (!sessionId) continue;
   277→
   278→    // CheckpointSessionMetadata — create or update
   279→    let sessionRecord = await db.checkpointSessionMetadata.findUnique({
   280→      where: { checkpointId_sessionId: { checkpointId, sessionId } },
   281→      select: { id: true },
   282→    });
   283→
   284→    if (!sessionRecord) {
   285→      let sessionTokenUsageId: number | null = null;
   286→      if (sessionMeta.token_usage) {
   287→        sessionTokenUsageId = await createTokenUsage(db, sessionMeta.token_usage);
   288→      }
   289→      sessionRecord = await db.checkpointSessionMetadata.create({
   290→        data: {
   291→          checkpointId,
   292→          sessionId,
   293→          cliVersion:       sessionMeta.cli_version       ?? null,
   294→          strategy:         sessionMeta.strategy          ?? null,
   295→          createdAt:        sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   296→          branch:           sessionMeta.branch            ?? null,
   297→          checkpointsCount: sessionMeta.checkpoints_count ?? 0,
   298→          agent:            sessionMeta.agent             ?? null,
   299→          turnId:           sessionMeta.turn_id           ?? null,
   300→          tokenUsageId:     sessionTokenUsageId,
   301→        },
   302→        select: { id: true },
   303→      });
   304→    } else {
   305→      await db.checkpointSessionMetadata.update({
   306→        where: { checkpointId_sessionId: { checkpointId, sessionId } },
   307→        data: {
   308→          cliVersion: sessionMeta.cli_version ?? null,
   309→          strategy:   sessionMeta.strategy    ?? null,
   310→          createdAt:  sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   311→          branch:     sessionMeta.branch      ?? null,
   312→          agent:      sessionMeta.agent       ?? null,
   313→          turnId:     sessionMeta.turn_id     ?? null,
   314→        },
   315→      });
   316→    }
   317→
   318→    // files_touched for session
   319→    for (const filePath of sessionMeta.files_touched ?? []) {
   320→      const filePathId = await upsertFilePath(db, filePath);
   321→      await db.checkpointSessionMetadataFilePath.upsert({
   322→        where: {
   323→          checkpointSessionMetadataId_filePathId: {
   324→            checkpointSessionMetadataId: sessionRecord.id,
   325→            filePathId,
   326→          },
   327→        },
   328→        create: { checkpointSessionMetadataId: sessionRecord.id, filePathId },
   329→        update: {},
   330→      });
   331→    }
   332→
   333→    // initial_attribution
   334→    if (sessionMeta.initial_attribution) {
   335→      const ia = sessionMeta.initial_attribution as Record<string, unknown>;
   336→      const iaData = {
   337→        calculatedAt:    ia.calculated_at ? new Date(ia.calculated_at as string) : null,
   338→        agentLines:      Number(ia.agent_lines      ?? 0),
   339→        humanAdded:      Number(ia.human_added      ?? 0),
   340→        humanModified:   Number(ia.human_modified   ?? 0),
   341→        humanRemoved:    Number(ia.human_removed    ?? 0),
   342→        totalCommitted:  Number(ia.total_committed  ?? 0),
   343→        agentPercentage: Number(ia.agent_percentage ?? 0),
   344→      };
   345→      await db.initialAttribution.upsert({
   346→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   347→        create: { checkpointSessionMetadataId: sessionRecord.id, ...iaData },
   348→        update: iaData,
   349→      });
   350→    }
   351→
   352→    // summary
   353→    if (sessionMeta.summary) {
   354→      const sm = sessionMeta.summary;
   355→      const summaryRecord = await db.checkpointSessionSummary.upsert({
   356→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   357→        create: { checkpointSessionMetadataId: sessionRecord.id, intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   358→        update: { intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   359→        select: { id: true },
   360→      });
   361→
   362→      // Recreate child arrays on every index pass (preserve status/subSessionId on OpenItem)
   363→      await Promise.all([
   364→        db.frictionItem.deleteMany( { where: { checkpointSessionSummaryId: summaryRecord.id } }),
   365→        db.repoLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   366→        db.codeLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   367→        db.workflowItem.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   368→      ]);
   369→
   370→      const creates: Promise<unknown>[] = [];
   371→
   372→      if (sm.open_items?.length) {
   373→        // Look up prior statuses for this session so they survive new checkpoints being indexed.
   374→        // Fetch ALL non-open prior items (not just exact matches) so we can fuzzy-match rephrased items.
   375→        const priorItems = await db.openItem.findMany({
   376→          where: {
   377→            checkpointSessionSummary: {
   378→              checkpointSessionMetadata: { sessionId },
   379→            },
   380→            status: { notIn: ["open"] },
   381→          },
   382→          select: { text: true, status: true, subSessionId: true },
   383→          distinct: ["text"],
   384→          orderBy: { id: "desc" },
   385→        });
   386→
   387→        // Build a map for exact matches and a list for fuzzy fallback
   388→        const priorByText = new Map(priorItems.map((p) => [p.text, p]));
   389→
   390→        // Jaccard similarity on word tokens (case-insensitive, punctuation-stripped)
   391→        function tokenize(s: string): Set<string> {
   392→          return new Set(s.toLowerCase().replace(/[^\w\s]/g, " ").split(/\s+/).filter(Boolean));
   393→        }
   394→        function jaccardSimilarity(a: string, b: string): number {
   395→          const ta = tokenize(a);
   396→          const tb = tokenize(b);
   397→          let intersection = 0;
   398→          for (const w of ta) if (tb.has(w)) intersection++;
   399→          const union = ta.size + tb.size - intersection;
   400→          return union === 0 ? 0 : intersection / union;
   401→        }
   402→
   403→        function findBestPrior(text: string) {
   404→          // Exact match first
   405→          if (priorByText.has(text)) return priorByText.get(text);
   406→          // Fuzzy fallback: best Jaccard match above 0.5 threshold
   407→          let best: { text: string; status: string; subSessionId: string | null } | undefined;
   408→          let bestScore = 0.5; // minimum threshold
   409→          for (const prior of priorItems) {
   410→            const score = jaccardSimilarity(text, prior.text);
   411→            if (score > bestScore) { bestScore = score; best = prior; }
   412→          }
   413→          return best;
   414→        }
   415→
   416→        creates.push(...sm.open_items.map((text) => {
   417→          const prior = findBestPrior(text);
   418→          return db.openItem.upsert({
   419→            where: { checkpointSessionSummaryId_text: { checkpointSessionSummaryId: summaryRecord.id, text } },
   420→            create: {
   421→              checkpointSessionSummaryId: summaryRecord.id,
   422→              text,
   423→              status: prior?.status ?? "open",
   424→              subSessionId: prior?.subSessionId ?? null,
   425→            },
   426→            update: {},
   427→          });
   428→        }));
   429→        // Remove open items that no longer appear in the source
   430→        creates.push(
   431→          db.openItem.deleteMany({
   432→            where: { checkpointSessionSummaryId: summaryRecord.id, text: { notIn: sm.open_items } },
   433→          })
   434→        );
   435→      } else {
   436→        creates.push(db.openItem.deleteMany({ where: { checkpointSessionSummaryId: summaryRecord.id } }));
   437→      }
   438→      if (sm.friction?.length) {
   439→        creates.push(db.frictionItem.createMany({
   440→          data: sm.friction.map((text) => ({ checkpointSessionSummaryId: summaryRecord.id, text })),
   441→        }));
   442→      }
   443→      if (sm.learnings?.repo?.length) {
   444→        creates.push(db.repoLearning.createMany({
   445→          data: sm.learnings.repo.map((text) => ({ checkpointSessionMetadataId: summaryRecord.id, text })),
   446→        }));
   447→      }
   448→      if (sm.learnings?.code?.length) {
   449→        creates.push(db.codeLearning.createMany({
   450→          data: sm.learnings.code.map(({ path, finding }) => ({
   451→            checkpointSessionMetadataId: summaryRecord.id,
   452→            path,
   453→            finding,
   454→          })),
   455→        }));
   456→      }
   457→      if (sm.learnings?.workflow?.length) {
   458→        creates.push(db.workflowItem.createMany({
   459→          data: sm.learnings.workflow.map((text) => ({ checkpointSessionMetadataId: summaryRecord.id, text })),
   460→        }));
   461→      }
   462→
   463→      await Promise.all(creates);
   464→    }
   465→  }
   466→
   467→  if (repoPath && !mappedCheckpointIds?.has(checkpointId)) {
   468→    await saveGitOidMapping(db, checkpointId, meta.branch, repoPath);
   469→  }
   470→}
   471→
   472→// ─── Full JSONL log indexer ───────────────────────────────────────────────────
   473→
   474→/**
   475→ * Parse a full.jsonl transcript file and write normalized rows to the LogEvent
   476→ * family of tables.  Already-indexed events (matched by uuid or messageId) are
   477→ * skipped so this function is safe to call multiple times on the same file.
   478→ *
   479→ * @param sessionLinkId  Optional FK into SessionLink so events can be traced
   480→ *                       back to the checkpoint/session that produced them.
   481→ */
   482→export async function indexFullJsonl(
   483→  db: PrismaClient,
   484→  transcriptPath: string,
   485→  sessionLinkId?: number,
   486→): Promise<{ events: number }> {
   487→  const content = readFileSync(transcriptPath, "utf8");
   488→  const events = parseFullJsonl(content);
   489→
   490→  // Pre-load known uuids / messageIds to skip duplicates without per-row queries.
   491→  const [existingUuids, existingMessageIds] = await Promise.all([
   492→    db.logEvent.findMany({ where: { uuid: { not: null } }, select: { uuid: true } })
   493→      .then((rows) => new Set(rows.map((r) => r.uuid as string))),
   494→    db.logEvent.findMany({ where: { messageId: { not: null } }, select: { messageId: true } })
   495→      .then((rows) => new Set(rows.map((r) => r.messageId as string))),
   496→  ]);
   497→
   498→  let count = 0;
   499→
   500→  for (const event of events) {
   501→    // Deduplication: skip if this event was already indexed.
   502→    if (event.uuid && existingUuids.has(event.uuid)) continue;
   503→    if (event.messageId && existingMessageIds.has(event.messageId)) continue;
   504→
   505→    const msg = event.message as Record<string, unknown> | undefined;
   506→
   507→    const logEvent = await db.logEvent.create({
   508→      data: {
   509→        uuid:            event.uuid            ?? null,
   510→        messageId:       event.messageId       ?? null,
   511→        sessionId:       event.sessionId       ?? null,
   512→        parentUuid:      event.parentUuid      ?? null,
   513→        type:            event.type,
   514→        timestamp:       event.timestamp ? new Date(event.timestamp) : null,
   515→        cwd:             event.cwd             ?? null,
   516→        gitBranch:       event.gitBranch       ?? null,
   517→        version:         event.version         ?? null,
   518→        slug:            event.slug            ?? null,
   519→        isSidechain:     event.isSidechain     ?? null,
   520→        userType:        event.userType        ?? null,
   521→        toolUseId:       event.toolUseID       ?? null,
   522→        parentToolUseId: event.parentToolUseID ?? null,
   523→        requestId:       (event.requestId as string | undefined) ?? null,
   524→        data:            JSON.stringify(event),
   525→        sessionLinkId:   sessionLinkId         ?? null,
   526→      },
   527→      select: { id: true },
   528→    });
   529→
   530→    // ── user / assistant: parse message content blocks ──────────────────────
   531→    if ((event.type === "user" || event.type === "assistant") && msg) {
   532→      const role = (msg.role as string | undefined) ?? event.type;
   533→      const rawContent = msg.content;
   534→      const contentArray: Record<string, unknown>[] =
   535→        Array.isArray(rawContent)
   536→          ? (rawContent as Record<string, unknown>[])
   537→          : typeof rawContent === "string"
   538→          ? [{ type: "text", text: rawContent }]
   539→          : [];
   540→
   541→      for (let i = 0; i < contentArray.length; i++) {
   542→        const c = contentArray[i];
   543→        const cType = (c.type as string | undefined) ?? "text";
   544→
   545→        // Stringify tool_result content if it's not already a string.
   546→        let toolResultContent: string | null = null;
   547→        if (cType === "tool_result") {
   548→          toolResultContent =
