          <Center p="xl"><Text c="dimmed" size="sm">No results found.</Text></Center>
        ) : (
          <Box style={{ display: "flex", flexDirection: "column", gap: 8 }}>
            {filtered.map((r) => (
              <ResultCard
                key={r.logContentId}
                r={r}
                onClick={() => navigate(`/sessions/${r.sessionId}`)}
              />
            ))}
          </Box>
        )}
      </Box>
    </ScrollArea>
  );
}

